@dataclass
class NonceEntry:
    nonce: str
    address: str
    created_at: float
    used: bool = False


class NonceStore:
    """Thread-safe nonce store with expiration."""

    def __init__(self, expiration_seconds: int = NONCE_EXPIRATION_SECONDS):
        self._store: dict[str, NonceEntry] = {}
        self._expiration = expiration_seconds

    def generate_nonce(self, address: str) -> str:
        """Generate a cryptographically secure nonce for an address."""
        address = address.lower()
        self._cleanup_expired()

        # Invalidate any existing nonces for this address
        keys_to_remove = [
            k for k, v in self._store.items()
            if v.address == address
        ]
        for k in keys_to_remove:
            del self._store[k]

        nonce = secrets.token_hex(32)
        self._store[nonce] = NonceEntry(
            nonce=nonce,
            address=address,
            created_at=time.time()
        )
        return nonce

    def validate_and_consume_nonce(self, nonce: str, address: str) -> bool:
        """Validate a nonce and mark it as used (one-time use)."""
        address = address.lower()
        self._cleanup_expired()

        entry = self._store.get(nonce)
        if entry is None:
            return False
        if entry.used:
            # Nonce replay detected
            logger.warning(f"Nonce replay attempt for address {address}")
            del self._store[nonce]
            return False
        if entry.address != address:
            logger.warning(f"Nonce address mismatch: expected {entry.address}, got {address}")
            return False
        if time.time() - entry.created_at > self._expiration:
            del self._store[nonce]
            return False

        # Mark as used and remove
        entry.used = True
        del self._store[nonce]
        return True

    def _cleanup_expired(self):
        """Remove expired nonces."""
        now = time.time()
        expired_keys = [
            k for k, v in self._store.items()
            if now - v.created_at > self._expiration
        ]
        for k in expired_keys:
            del self._store[k]


class TokenBlacklist:
    """Simple token blacklist for logout/revocation."""

    def __init__(self):
        self._blacklist: dict[str, float] = {}

    def revoke(self, token_id: str, expiry: float):
        self._blacklist[token_id] = expiry
        self._cleanup()

    def is_revoked(self, token_id: str) -> bool:
        self._cleanup()
        return token_id in self._blacklist

    def _cleanup(self):
        now = time.time()
        expired = [k for k, v in self._blacklist.items() if v < now]
        for k in expired:
            del self._blacklist[k]


# Initialize stores
nonce_store = NonceStore()
token_blacklist = TokenBlacklist()
w3 = Web3()

# Ethereum address validation regex
ETH_ADDRESS_REGEX = re.compile(r'^0x[0-9a-fA-F]{40}$')
HEX_REGEX = re.compile(r'^[0-9a-fA-F]+$')


def is_valid_eth_address(address: str) -> bool:
    """Validate Ethereum address format."""
    if not isinstance(address, str):
        return False
    if not ETH_ADDRESS_REGEX.match(address):
        return False
    # Verify checksum if mixed case
    if address != address.lower() and address != address.upper():
        try:
            return Web3.is_checksum_address(address)
        except Exception:
            return False
    return True


def create_sign_message(address: str, nonce: str) -> str:
    """Create a deterministic message for signing."""
    return (
        f"Sign this message to authenticate with our Web3 service.\n\n"
        f"Address: {address.lower()}\n"
        f"Nonce: {nonce}\n\n"
        f"This signature will not trigger a blockchain transaction or cost any gas fees."
    )


def recover_signer(message: str, signature: str) -> Optional[str]:
    """Recover the signer address from a signed message."""
    try:
        if not isinstance(signature, str):
            return None
        # Validate signature format
        sig = signature
        if sig.startswith('0x'):
            sig_hex = sig[2:]
        else:
            sig_hex = sig
        if not HEX_REGEX.match(sig_hex):
            return None
        if len(sig_hex) != 130:  # 65 bytes = 130 hex chars
            return None

        encoded_message = encode_defunct(text=message)
        recovered_address = w3.eth.account.recover_message(
            encoded_message,
            signature=signature
        )
        return recovered_address
    except Exception as e:
        logger.error(f"Signature recovery failed: {e}")
        return None


def create_jwt_token(address: str) -> tuple[str, str, datetime]:
    """Create a JWT token for an authenticated address."""
    token_id = secrets.token_hex(16)
    expiry = datetime.utcnow() + timedelta(hours=JWT_EXPIRATION_HOURS)
    payload = {
        'sub': address.lower(),
        'jti': token_id,
        'iat': datetime.utcnow(),
        'exp': expiry,
        'type': 'access'
    }
    token = jwt.encode(payload, JWT_SECRET, algorithm=JWT_ALGORITHM)
    return token, token_id, expiry


def verify_jwt_token(token: str) -> Optional[dict]:
    """Verify and decode a JWT token."""
    try:
        payload = jwt.decode(token, JWT_SECRET, algorithms=[JWT_ALGORITHM])
        if token_blacklist.is_revoked(payload.get('jti', '')):
            return None
        return payload
    except jwt.ExpiredSignatureError:
        logger.info("Expired token presented")
        return None
    except jwt.InvalidTokenError as e:
        logger.warning(f"Invalid token: {e}")
        return None


def require_auth(f):
    """Decorator to require JWT authentication."""
    from functools import wraps

    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        if not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Missing or invalid Authorization header'}), 401

        token = auth_header[7:]
        if len(token) > 4096:
            return jsonify({'error': 'Token too large'}), 401

        payload = verify_jwt_token(token)
        if payload is None:
            return jsonify({'error': 'Invalid or expired token'}), 401

        request.user_address = payload['sub']
        request.token_payload = payload
        return f(*args, **kwargs)

    return decorated


@app.route('/auth/nonce', methods=['POST'])
@limiter.limit("20 per minute")
def get_nonce():
    """
    Request a nonce for signing.
    Body: {"address": "0x..."}
    """
    data = request.get_json(silent=True)
    if not data:
        return jsonify({'error': 'Invalid JSON body'}), 400

    address = data.get('address', '')
    if not is_valid_eth_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400

    nonce = nonce_store.generate_nonce(address)
    message = create_sign_message(address, nonce)

    logger.info(f"Nonce generated for address {address.lower()}")

    return jsonify({
        'nonce': nonce,
        'message': message
    }), 200


@app.route('/auth/verify', methods=['POST'])
@limiter.limit("10 per minute")
def verify_signature():
    """
    Verify a signed message and return a JWT token.
    Body: {"address": "0x...", "signature": "0x...", "nonce": "..."}
    """
    data = request.get_json(silent=True)
    if not data:
        return jsonify({'error': 'Invalid JSON body'}), 400

    address = data.get('address', '')
    signature = data.get('signature', '')
    nonce = data.get('nonce', '')

    # Validate inputs
    if not is_valid_eth_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400

    if not isinstance(signature, str) or len(signature) > 256:
        return jsonify({'error': 'Invalid signature format'}), 400

    if not isinstance(nonce, str) or len(nonce) > 128:
        return jsonify({'error': 'Invalid nonce format'}), 400

    # Validate and consume nonce (prevents replay)
    if not nonce_store.validate_and_consume_nonce(nonce, address):
        logger.warning(f"Invalid or expired nonce for address {address.lower()}")
        return jsonify({'error': 'Invalid, expired, or already used nonce'}), 401

    # Reconstruct the expected message
    message = create_sign_message(address, nonce)

    # Recover signer from signature
    recovered_address = recover_signer(message, signature)
    if recovered_address is None:
        logger.warning(f"Signature recovery failed for address {address.lower()}")
        return jsonify({'error': 'Invalid signature'}), 401

    # Constant-time comparison of addresses
    if not hmac.compare_digest(
        recovered_address.lower().encode(),
        address.lower().encode()
    ):
        logger.warning(
            f"Address mismatch: claimed {address.lower()}, "
            f"recovered {recovered_address.lower()}"
        )
        return jsonify({'error': 'Signature does not match claimed address'}), 401

    # Authentication successful - create JWT
    token, token_id, expiry = create_jwt_token(address)

    logger.info(f"Authentication successful for address {address.lower()}")

    return jsonify({
        'token': token,
        'address': address.lower(),
        'expires_at': expiry.isoformat() + 'Z'
    }), 200


@app.route('/auth/logout', methods=['POST'])
@require_auth
def logout():
    """Revoke the current JWT token."""
    payload = request.token_payload
    token_id = payload.get('jti', '')
    exp = payload.get('exp', 0)

    token_blacklist.revoke(token_id, exp)
    logger.info(f"Token revoked for address {request.user_address}")

    return jsonify({'message': 'Successfully logged out'}), 200


