@app.route('/auth/refresh', methods=['POST'])
@limiter.limit("10 per minute")
@require_auth
def refresh_token():
    """Refresh the JWT token (issue a new one and revoke the old)."""
    old_payload = request.token_payload
    old_token_id = old_payload.get('jti', '')
    old_exp = old_payload.get('exp', 0)

    # Revoke old token
    token_blacklist.revoke(old_token_id, old_exp)

    # Issue new token
    token, token_id, expiry = create_jwt_token(request.user_address)

    logger.info(f"Token refreshed for address {request.user_address}")

    return jsonify({
        'token': token,
        'address': request.user_address,
        'expires_at': expiry.isoformat() + 'Z'
    }), 200


